package form;
import controller.AuthController;import model.User;import util.UIUtils;import javax.swing.*;import java.awt.*;
public class LoginFrame extends JFrame{private final JTextField user=UIUtils.textField(18);private final JPasswordField pass=new JPasswordField(18);public LoginFrame(){setTitle("SKM - Login");setDefaultCloseOperation(EXIT_ON_CLOSE);JPanel p=UIUtils.card();p.setLayout(new GridBagLayout());GridBagConstraints g=new GridBagConstraints();g.insets=new Insets(8,8,8,8);g.gridx=0;g.gridy=0;g.gridwidth=2;p.add(UIUtils.schoolLogo(80),g);g.gridy++;p.add(new JLabel("Sistem Keuangan Madrasah"),g);g.gridwidth=1;g.gridy++;p.add(UIUtils.formLabel("Username"),g);g.gridx=1;p.add(user,g);g.gridx=0;g.gridy++;p.add(UIUtils.formLabel("Password"),g);g.gridx=1;p.add(pass,g);JButton b=UIUtils.button("Masuk",UIUtils.BLUE);g.gridx=0;g.gridy++;g.gridwidth=2;p.add(b,g);add(p);b.addActionListener(e->login());pack();setLocationRelativeTo(null);}private void login(){try{AuthController a=new AuthController();User u=a.login(user.getText(),new String(pass.getPassword()));if(u!=null){new MainFrame(u).setVisible(true);dispose();}else JOptionPane.showMessageDialog(this,"Login gagal");}catch(Exception ex){JOptionPane.showMessageDialog(this,"DB belum siap: "+ex.getMessage());new MainFrame(new User(1,"Admin Demo","admin","","Super Admin",null)).setVisible(true);dispose();}}}
